import type { PointerEvent, ReactNode } from "react";

export type CanvasNodeStatusTone =
  | "accessible"
  | "available"
  | "binding"
  | "bound"
  | "complete"
  | "creating"
  | "degraded"
  | "deleting"
  | "error"
  | "failed"
  | "inaccessible"
  | "pending"
  | "progressing"
  | "ready"
  | "running"
  | "shutdown"
  | "stopped"
  | "stopping"
  | "succeeded"
  | "unhealthy"
  | "unknown";

export interface CanvasNodeStatus {
  label: string;
  tone?: CanvasNodeStatusTone;
}

export interface CanvasNodeInteractionState {
  dragging?: boolean;
  selected?: boolean;
}

export type CanvasNodeConnectionSide = "bottom" | "left" | "right" | "top";

export type CanvasNodeConnectionEvent = PointerEvent<HTMLButtonElement>;

export interface CanvasNodeState {
  interaction?: CanvasNodeInteractionState;
}

export interface CanvasNodeActions {
  collapse?: () => void;
  expand?: () => void;
  startConnection?: (
    side: CanvasNodeConnectionSide,
    event: CanvasNodeConnectionEvent
  ) => void;
}

export interface CanvasNodeMeta {
  expanded: boolean;
}

export interface CanvasNodeContextValue {
  actions: Required<Pick<CanvasNodeActions, "collapse" | "expand">> &
    Omit<CanvasNodeActions, "collapse" | "expand">;
  meta: CanvasNodeMeta;
  state: CanvasNodeState;
}

export interface CanvasNodeProviderProps {
  children?: ReactNode;
  value: CanvasNodeContextValue;
}

export interface CanvasNodeRootProps {
  children?: ReactNode;
  defaultExpanded?: boolean;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  onExpandedChange?: (expanded: boolean) => void;
  onStartConnection?: CanvasNodeActions["startConnection"];
}

"use client";

import { createContext, use } from "react";

import type { CanvasNodeContextValue } from "./canvas-node.types";

export const CanvasNodeContext = createContext<CanvasNodeContextValue | null>(
  null
);

export function useCanvasNode(): CanvasNodeContextValue {
  const value = use(CanvasNodeContext);

  if (!value) {
    throw new Error(
      "CanvasNode: compound components must be used within CanvasNode.Root"
    );
  }

  return value;
}

"use client";

import { CanvasNodeContext } from "./canvas-node.context";
import type { CanvasNodeProviderProps } from "./canvas-node.types";

export function CanvasNodeProvider({
  children,
  value,
}: CanvasNodeProviderProps) {
  return <CanvasNodeContext value={value}>{children}</CanvasNodeContext>;
}

"use client";

import { useCallback, useMemo, useState } from "react";

import { CanvasNodeProvider } from "./canvas-node.provider";
import type {
  CanvasNodeConnectionEvent,
  CanvasNodeConnectionSide,
  CanvasNodeContextValue,
  CanvasNodeRootProps,
} from "./canvas-node.types";

export function CanvasNodeRoot({
  children,
  defaultExpanded = false,
  expanded,
  interaction,
  onExpandedChange,
  onStartConnection,
}: CanvasNodeRootProps) {
  const [internalExpanded, setInternalExpanded] = useState(defaultExpanded);
  const expandedControlled = expanded !== undefined;
  const resolvedExpanded = expanded ?? internalExpanded;

  const setExpandedState = useCallback(
    (nextExpanded: boolean) => {
      if (!expandedControlled) {
        setInternalExpanded(nextExpanded);
      }

      onExpandedChange?.(nextExpanded);
    },
    [expandedControlled, onExpandedChange]
  );

  const collapse = useCallback(() => {
    setExpandedState(false);
  }, [setExpandedState]);

  const expand = useCallback(() => {
    setExpandedState(true);
  }, [setExpandedState]);

  const startConnection = useCallback(
    (side: CanvasNodeConnectionSide, event: CanvasNodeConnectionEvent) => {
      onStartConnection?.(side, event);
    },
    [onStartConnection]
  );

  const value = useMemo(
    (): CanvasNodeContextValue => ({
      actions: {
        collapse,
        expand,
        startConnection,
      },
      meta: {
        expanded: resolvedExpanded,
      },
      state: {
        interaction,
      },
    }),
    [collapse, expand, interaction, resolvedExpanded, startConnection]
  );

  return <CanvasNodeProvider value={value}>{children}</CanvasNodeProvider>;
}

"use client";

import { cn } from "@workspace/ui/lib/utils";
import type { MouseEvent, PointerEvent, ReactNode } from "react";
import { useCallback, useState } from "react";

import { useCanvasNode } from "./canvas-node.context";

function isInsideSurface(
  currentTarget: HTMLElement,
  target: EventTarget | null
) {
  if (!(target instanceof Node)) {
    return false;
  }

  const surfaceEl = currentTarget.querySelector(
    '[data-slot="canvas-node-surface"]'
  );
  return surfaceEl?.contains(target) ?? false;
}

function stopOutsideSurface<E extends MouseEvent | PointerEvent>(event: E) {
  if (!isInsideSurface(event.currentTarget as HTMLElement, event.target)) {
    event.stopPropagation();
  }
}

export function CanvasNodeFrame({
  children,
  className,
}: {
  children?: ReactNode;
  className?: string;
}) {
  const {
    meta: { expanded },
    state: { interaction },
  } = useCanvasNode();
  const selected = interaction?.selected ?? false;
  const dragging = interaction?.dragging ?? false;
  const [hoverIntent, setHoverIntent] = useState(false);

  const showHoverIntent = useCallback(() => {
    if (dragging) {
      setHoverIntent(false);
      return;
    }

    setHoverIntent(true);
  }, [dragging]);

  const hideHoverIntent = useCallback(() => {
    setHoverIntent(false);
  }, []);

  return (
    // biome-ignore lint/a11y/noNoninteractiveElementInteractions: frame scopes canvas hit targets and hover state; interaction stays on child controls.
    // biome-ignore lint/a11y/noStaticElementInteractions: frame is a visual/state wrapper, not an interactive control.
    // biome-ignore lint/a11y/useKeyWithClickEvents: mouse handlers only stop propagation outside the surface.
    <div
      className={cn("canvas-node-frame relative", className)}
      data-dragging={dragging || undefined}
      data-hover-intent={hoverIntent || undefined}
      data-selected={selected || undefined}
      data-slot="canvas-node-frame"
      data-state={expanded ? "expanded" : "collapsed"}
      onClick={stopOutsideSurface}
      onPointerDown={stopOutsideSurface}
      onPointerEnter={showHoverIntent}
      onPointerLeave={hideHoverIntent}
    >
      {children}
    </div>
  );
}

